const locationThreshold = 0.0015; // approx ~150m

function isNear(lat1, lon1, lat2, lon2) {
  const toNum = s => parseFloat(s);
  lat1 = toNum(lat1);
  lon1 = toNum(lon1);
  lat2 = toNum(lat2);
  lon2 = toNum(lon2);
  if (isNaN(lat1) || isNaN(lon1) || isNaN(lat2) || isNaN(lon2)) return false;
  const latDiff = Math.abs(lat1 - lat2);
  const lonDiff = Math.abs(lon1 - lon2);
  return latDiff <= locationThreshold && lonDiff <= locationThreshold;
}

