const homeLatitude = 40.7128; // example home latitude
const homeLongitude = -74.0060; // example home longitude
const locationTolerance = 0.01; // approx ~1km tolerance

function isAtHome(latStr, lonStr) {
  const lat = parseFloat(latStr);
  const lon = parseFloat(lonStr);
  if (isNaN(lat) || isNaN(lon)) return false;
  return Math.abs(lat - homeLatitude) <= locationTolerance && Math.abs(lon - homeLongitude) <= locationTolerance;
}

