function isNear(lat1, lon1, lat2, lon2) {
  const toNum = s => parseFloat(s);
  lat1 = toNum(lat1);
  lon1 = toNum(lon1);
  lat2 = toNum(lat2);
  lon2 = toNum(lon2);
