const frontDoorLongitude = '-74.005974';
const tolerance = 0.0005;
function isAtFrontDoor(lat, lon) {
  const latNum = parseFloat(lat);
  const lonNum = parseFloat(lon);
  if (isNaN(latNum) || isNaN(lonNum)) return false;
  return Math.abs(latNum - parseFloat(frontDoorLatitude)) <= tolerance && Math.abs(lonNum - parseFloat(frontDoorLongitude)) <= tolerance;
}
